const fs = require('fs');
let persona = '';
try {
  persona = fs.readFileSync('/etc/n8n/agents/kowalski.md', 'utf8');
} catch (e) {
  persona = 'Kowalski, tactical and military-grade database analyst agent.';
}

const schemaRows = $('Scan DB Structure').all();
const directiveRows = $('Get Directives').all();
const directives = directiveRows.length > 0 ? directiveRows.map((r, i) => (i + 1) + '. ' + r.json.directive).join('\n') : 'No directives provided.';

if (schemaRows.length === 0) {
  return [{ json: { text: 'No database tables found.', directives, kowalski_persona: persona } }];
}

const schemas = {};
schemaRows.forEach(row => {
  const d = row.json;
  if (!schemas[d.schema_name]) {
    schemas[d.schema_name] = {};
  }
  if (!schemas[d.schema_name][d.table_name]) {
    schemas[d.schema_name][d.table_name] = [];
  }
  schemas[d.schema_name][d.table_name].push({
    column: d.column_name,
    type: d.data_type,
    description: d.column_description || ''
  });
});

let text = 'PostgreSQL Database Schema and Column Documentation:\n\n';
for (const [schemaName, tables] of Object.entries(schemas)) {
  text += `Schema: ${schemaName}\n`;
  for (const [tableName, columns] of Object.entries(tables)) {
    text += `  Table: ${tableName}\n`;
    columns.forEach(col => {
      text += `    - ${col.column} (${col.type})${col.description ? ' // ' + col.description : ''}\n`;
    });
  }
  text += '\n';
}

// Cap schema to avoid overwhelming small LLMs (gemma4:31b context limit)
const MAX_SCHEMA_CHARS = 6000;
if (text.length > MAX_SCHEMA_CHARS) {
  text = text.substring(0, MAX_SCHEMA_CHARS) + '\n...[schema truncated for LLM context limit]';
}

return [{ json: { text, directives, kowalski_persona: persona } }];

const FALLBACK_HYPOTHESES = [
  {
    hypothesis: 'Most recently ingested content comes from Reddit versus Substack.',
    query: "SELECT 'reddit' AS source, MAX(created_at) AS latest FROM s_reddit.posts UNION ALL SELECT 'substack', MAX(published_at) FROM s_substack.posts ORDER BY latest DESC LIMIT 5;"
  },
  {
    hypothesis: 'LinkedIn messages represent the majority of personal communication data.',
    query: "SELECT COUNT(*) AS total_messages FROM s_linkedin.messages;"
  },
  {
    hypothesis: 'There are active subreddits being monitored with recent posts.',
    query: "SELECT s.name AS subreddit_name, COUNT(*) AS post_count FROM s_reddit.posts p JOIN s_reddit.subreddits_monitored s ON p.subreddit_id = s.id GROUP BY s.name ORDER BY post_count DESC LIMIT 10;"
  }
];

const raw = $input.first().json.response || '';
let jsonStr = raw.trim();
const firstBrace = jsonStr.indexOf('{');
const lastBrace = jsonStr.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
}

if (!jsonStr) {
  console.log('LLM returned empty response, using fallback queries.');
  return FALLBACK_HYPOTHESES.map(h => ({ json: h }));
}

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  console.log('Failed to parse LLM JSON, using fallback queries. Error: ' + e.message);
  return FALLBACK_HYPOTHESES.map(h => ({ json: h }));
}

const hypotheses = Array.isArray(parsed.hypotheses) ? parsed.hypotheses.filter(h => h && h.query) : [];
if (hypotheses.length === 0) {
  console.log('No valid hypotheses in LLM response, using fallback queries.');
  return FALLBACK_HYPOTHESES.map(h => ({ json: h }));
}

return hypotheses.map(h => ({
  json: {
    hypothesis: h.hypothesis || 'Unnamed hypothesis',
    query: h.query
  }
}));

const results = $input.all();
const originalInput = $('Format Schema for LLM').first().json;

const MAX_INDIVIDUAL_RESULT_CHARS = 300; // Keep each individual query result short
const MAX_TOTAL_SUMMARY_CHARS = 5000;   // Keep the overall summary size within bounds

let resultsText = '';
results.forEach((item, index) => {
  const splitList = $('Split Queries').all();
  const pairedIdx = item.pairedItem && item.pairedItem.item !== undefined ? item.pairedItem.item : index;
  const h = splitList[pairedIdx] ? splitList[pairedIdx].json : {};
  const query = h.query || 'Unknown query';
  const hypothesis = h.hypothesis || 'Unknown hypothesis';
  let queryResult = '';
  try {
    queryResult = JSON.stringify(item.json);
  } catch (e) {
    queryResult = 'Error stringifying result: ' + e.message;
  }
  if (queryResult.length > MAX_INDIVIDUAL_RESULT_CHARS) {
    queryResult = queryResult.substring(0, MAX_INDIVIDUAL_RESULT_CHARS) + '...[truncated]';
  }

  const entry = `Hypothesis ${index + 1}: ${hypothesis}\nSQL Query Run: ${query}\nResult Data: ${queryResult}\n\n`;

  // Check if adding this entry exceeds our overall limit
  if ((resultsText + entry).length > MAX_TOTAL_SUMMARY_CHARS) {
    resultsText += `...\n[Remaining ${results.length - index} hypothesis results truncated to prevent LLM context limit overflow]`;
    return;
  }
  resultsText += entry;
});

return [{
  json: {
    directives: originalInput.directives,
    kowalski_persona: originalInput.kowalski_persona,
    results_summary: resultsText.trim()
  }
}];

const inputData = $input.first().json;
const response = inputData.content || inputData.output || inputData.response || inputData.text || '';
let report = typeof response === 'string' ? response.trim() : JSON.stringify(response);

// Convert markdown tables into neat, readable lists for Slack using clean indent-based lines
if (report.includes('|')) {
  const lines = report.split('\n');
  const formattedLines = [];
  let inTable = false;
  for (let line of lines) {
    if (line.trim().startsWith('|')) {
      if (!inTable) {
        inTable = true;
      }
      const cells = line.split('|').map(c => c.trim()).filter(c => c !== '');
      // Skip header and separator lines
      if (cells.length > 0 && !cells[0].includes('---') && !cells[0].toLowerCase().includes('hypothesis') && !cells[0].toLowerCase().includes('sql query')) {
        const hypothesisNum = cells[0];
        const query = cells[1] ? `\`${cells[1].replace(/`/g, '')}\`` : '';
        const result = cells[2] ? `\`${cells[2].replace(/`/g, '')}\`` : '';
        const verdict = cells[3] ? `*${cells[3]}*` : '';
        const analysis = cells[4] || '';

        formattedLines.push(`*Hypothesis ${hypothesisNum}*: ${verdict}\n  • *Query:* ${query}\n  • *Result:* ${result}\n  • *Analysis:* ${analysis}`);
      }
    } else {
      if (inTable) {
        inTable = false;
        formattedLines.push(''); // add spacer
      }
      formattedLines.push(line);
    }
  }
  report = formattedLines.join('\n');
}

// Translate standard markdown bold (**text**) to Slack bold (*text*)
report = report.replace(/\*\*(.*?)\*\*/g, '*$1*');

// Normalize list bullet styling without utilizing the blue diamond emoji
report = report.split('\n').map(line => {
  let trimmed = line.trim();
  // Check if it starts with standard markdown list indicators
  if (trimmed.startsWith('* ') || trimmed.startsWith('- ') || trimmed.startsWith('• ') || trimmed.startsWith('🔹 ')) {
    const indent = line.substring(0, line.indexOf(trimmed[0]));
    // Remove the indicator entirely or replace with clean bullet
    const newIndicator = indent.length > 0 ? '•' : '';
    const remainingText = trimmed.substring(trimmed.indexOf(' ') + 1);
    return indent + (newIndicator ? newIndicator + ' ' : '') + remainingText;
  }
  return line;
}).join('\n');

// Clean up pseudo-markdown links like <url|Label> or <s_reddit.posts|s_reddit.posts>
report = report.replace(/<url\|(.*?)>/g, '*[$1]*');
report = report.replace(/<s_(\w+)\.(\w+)\|s_(\w+)\.(\w+)>/g, '*[s_$1.$2]*');
report = report.replace(/<s_(\w+)\.(\w+)\|(\w+)>/g, '*[$3]*');

// Translate typical markdown emojis or missing slack shortcodes
report = report
  .replace(/:saluting_face:/g, '🫡')
  .replace(/:chart_with_upwards_trend:/g, '📈')
  .replace(/:mag:/g, '🔍')
  .replace(/:bulb:/g, '💡')
  .replace(/\n{3,}/g, '\n\n'); // normalize multiple newlines

const text = report.length > 0
  ? report
  : '⚠️ Kowalski returned an empty report. The LLM may have timed out or exceeded its context window. Check the Auto EDA execution log for details.';
return [{ json: { report_text: text } }];
